UPDATE loan_application SET
application_no=#{applicationNo}, product_code=#{productCode}, applicant_name=#{applicantName},
id_card_no=#{idCardNo}, mobile=#{mobile}, loan_amount=#{loanAmount}, loan_term=#{loanTerm},
employment_type=#{employmentType}, company_name=#{companyName}, work_years=#{workYears},
status=#{status}, current_step=#{currentStep}, channel_code=#{channelCode}, owner_username=#{ownerUsername}, updated_at=#{updatedAt}
WHERE id=#{applicationId}

UPDATE loan_application SET status=#{toStatus}, current_step=#{currentStep},
version=version+1, updated_at=#{updatedAt}
WHERE id=#{applicationId} AND status=#{expectedStatus}
